VALUES
  ('fire-eq-eng-moex-00513', 'fire-eq-eng', 'fire-eq-eng-moex-108-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防設備師及消防設備士管理辦法之規定，下列有關消防設備師之敘述，何者正確？', '["消防設備師及消防設備士執行業務，應備業務登記簿並至少保存3年", "參加講習所需經費由受訓人員自行負擔，其金額由講習單位報請地方主管機關核定後實施", "參加中央主管機關舉辦之2小時消防安全設備設計講習會，取得20分積分證明", "擔任中央主管機關舉辦之2小時消防安全設備檢修專業訓練課程講座，取得40分積分證明"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:16+00:00", "source_pdf_sha1": "fe44dcbaac84", "answer_pdf_sha1": "49cadaaff8fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00514', 'fire-eq-eng', 'fire-eq-eng-moex-108-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防安全設備檢修專業機構管理辦法之規定，有關消防安全設備檢修專業機構之敘述，何', '["投保責任保險，保險期間總保險金額：新臺幣2千萬元", "檢修機構應於年度終 結後6個月內，檢具書表，報請內政部備查", "檢修機構聘用消防設備師，應於事實發生之 日起15日內，檢附文件報請內政部備查", "合格證書有效期限為3年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:16+00:00", "source_pdf_sha1": "fe44dcbaac84", "answer_pdf_sha1": "49cadaaff8fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00515', 'fire-eq-eng', 'fire-eq-eng-moex-108-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，有關公共危險物品之種 類名稱及管制量敘述，何者正確？', '["亞硝酸鹽類：第一類/氧化性固體，管制量100公斤", "固態酒精：第二類/易燃性固體，管制量1000公斤", "三聚甲醛：第四類/易燃液體，管制量50公斤", "三氯矽甲烷：第三類/發火性液體、發火性固體及禁水性物質，管制量100公斤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:16+00:00", "source_pdf_sha1": "fe44dcbaac84", "answer_pdf_sha1": "49cadaaff8fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00516', 'fire-eq-eng', 'fire-eq-eng-moex-108-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，有關液化石油氣販賣場 所儲放液化石油氣，得設容器保管室儲放，容器保管室應符合：', '["為儲存場所專用", "位於販賣場所同一建築基地之地面二層建築物", "屋頂應以輕質金屬板或其他輕質不燃材料覆蓋，並距離地面2公尺以上", "出入口應設置30分鐘以上防火時效之防火門"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:16+00:00", "source_pdf_sha1": "fe44dcbaac84", "answer_pdf_sha1": "49cadaaff8fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00517', 'fire-eq-eng', 'fire-eq-eng-moex-108-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依可燃性高壓氣體儲存場所防爆牆設置基準之規定，有關防爆牆敘述，何者正確？', '["防爆牆分為鋼筋混凝土製及混凝土空心磚製等二種", "防爆牆應設置於堅固基礎上，其強度應能承受可能預料之氣體爆炸衝擊", "混凝土空心磚製防爆牆之牆縫塗裝面得粉刷水泥漿", "鋼筋混凝土製防爆牆應施以防銹處理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:16+00:00", "source_pdf_sha1": "fe44dcbaac84", "answer_pdf_sha1": "49cadaaff8fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00518', 'fire-eq-eng', 'fire-eq-eng-moex-108-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依原有合法建築物防火避難設施及消防設備改善辦法之規定，有關原有合法建築物 11 層以 上之樓層面積區劃敘述，何者正確？', '["樓地板面積超過100平方公尺者，應按每50平方公尺，以具有1小時以上防火時效之牆 壁、樓地板及防火設備區劃分隔", "自地板面起1公尺以上之室內牆面及天花板均使用耐燃一級材料裝修者，得按每150平方 公尺，以具有1小時以上防火時效之牆壁、樓地板及防火設備區劃分隔", "備有效自動滅火設備者，得免計算其有效範圍樓地板面積之三分之一", "室內牆面及天花板（包括底材）均以耐燃一級材料裝修者，得按每500平方公尺範圍內， 以具有1小時以上防火時效之牆壁、樓地板及防火設備區劃分隔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:16+00:00", "source_pdf_sha1": "fe44dcbaac84", "answer_pdf_sha1": "49cadaaff8fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00519', 'fire-eq-eng', 'fire-eq-eng-moex-108-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編之規定，下列何者正確？', '["建築物地面層超過5層或高度超過15公尺者，每增加一層樓或4公尺，其空地應增加百 分之二", "商業區之法定騎樓或住宅區面臨 10 公尺以上道路之法定騎樓所占面積不計入基地面積及 建築面積", "防火門窗周邊25公分範圍內之牆壁應以不燃材料建造", "防火門之門扇寬度應在70公分以上，高度應在160公分以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:16+00:00", "source_pdf_sha1": "fe44dcbaac84", "answer_pdf_sha1": "49cadaaff8fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
